{"code":"import json, re
# Load MongoDB activity query results
with open(var_call_zqpzazna1jCnfKTTzQ6DPwWC, 'r', encoding='utf-8') as f:
    paper_docs = json.load(f)
# Load activity-related citations
with open(var_call_d589z7pHY5g3uVAtPA2Hxqvw, 'r', encoding='utf-8') as f:
    activity_citations = json.load(f)

# Build citation lookup
cit_lookup = {rec['title'].strip(): int(rec['total_citations']) for rec in activity_citations}

results = []
for doc in paper_docs:
    filename = doc.get('filename','')
    text = doc.get('text','') or ''
    if not filename:
        continue
    title = filename[:-4] if filename.lower().endswith('.txt') else filename
    # find publication year in header (first 800 chars)
    head = text[:800]
    year = None
    # search for CHI 2016 pattern or standalone 2016
    m = re.search(r"(CHI|Ubicomp|UbiComp|CSCW|DIS|PervasiveHealth|WWW|IUI|OzCHI|TEI|AH)[^\n,]*\b(19|20)\d{2}\b", head, flags=re.I)
    if m:
        y = re.search(r"\b(19|20)\d{2}\b", m.group(0))
        if y:
            year = int(y.group(0))
    else:
        y2 = re.search(r"\b(19|20)\d{2}\b", head)
        if y2:
            year = int(y2.group(0))
    # fallback: search entire text for 2016
    if year is None and re.search(r"\b2016\b", text):
        year = 2016

    # check domain indicators for physical activity
    domain_indicators = [r'physical\s*activity', r'fitness', r'exercise', r'activity tracking', r'activity tracker', r'physical activity tracker']
    is_physical = any(re.search(pat, text, flags=re.I) for pat in domain_indicators)

    if year == 2016 and is_physical:
        # get citation count from lookup, try normalization if not found
        tc = cit_lookup.get(title)
        if tc is None:
            # try normalized matching
            def norm(s):
                return re.sub(r"[^A-Za-z0-9]", "", s).lower()
            ntitle = norm(title)
            for k,v in cit_lookup.items():
                if norm(k) == ntitle:
                    tc = v
                    break
        if tc is None:
            tc = 0
        results.append({"title": title, "total_citations": tc})

# deduplicate
seen = set()
unique = []
for r in results:
    if r['title'] not in seen:
        seen.add(r['title'])
        unique.append(r)

print("__RESULT__:")
print(json.dumps(unique))"}

